#include <stdio.h>
int main() {
    int T, N, A[100000], i, j, sum;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        sum = 0;
        for (i = 0; i < N; i++) {
            int xor_sum = 0;
            for (j = i; j < N; j++) {
                xor_sum ^= A[j];
                sum += xor_sum;
            }
        }
        printf("%d\n", sum);
    }
    return 0;
}

