import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            int sum = 0;
            for (int i = 0; i < N; i++) {
                int xor_sum = 0;
                for (int j = i; j < N; j++) {
                    xor_sum ^= A[j];
                    sum += xor_sum;
                }
            }
            System.out.println(sum);
        }
    }
}

