let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    let sum = 0;
    for (let j = 0; j < N; j++) {
        let xor_sum = 0;
        for (let k = j; k < N; k++) {
            xor_sum ^= A[k];
            sum += xor_sum;
        }
    }
    console.log(sum);
